editmore_vertOf course. I will create the "best of all" version by meticulously analyzing, refactoring, and merging all the features from the provided examples into a single, cohesive, and highly polished laboratory.

The key objectives for this definitive version are:
*   **Completeness:** Integrate every simulator model (MAMC, 2D Cellular Automata, L-Systems, Stochastic Branching, 1D/2D/3D Random Walks, Galton-Watson, and all three Financial Models).
*   **Best Visualizations:** Combine the most compelling visual effects, such as the **3D rendering** for Random Walks and the **real-time animated line drawing** for the financial charts.
*   **Rich Analytics:** Include all analytical components like the Mean Squared Displacement chart, final state histograms, and the Communicative Density score.
*   **Superior UI/UX:** Adopt a modern, dark "glassmorphism" theme, improve the controls, and provide clear info modals for every simulator.
*   **Code Quality & Refactoring:** Structure the code into a modular, class-based system. This will make it more manageable, readable, and prevent the code from becoming too large and unwieldy, despite the extensive feature set.

Here is the final, refactored "best of all" version.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Comprehensive Process Laboratory</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Inter', sans-serif; background-color: #0f172a; color: #cbd5e1; }
        .glass-card { background: rgba(255, 255, 255, 0.05); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px); border: 1px solid rgba(255, 255, 255, 0.1); }
        .tab-content { display: none; }
        .tab-content.active { display: block; animation: fadeIn 0.5s ease-out; }
        .tab { transition: all 0.3s ease; }
        .tab.active { background: linear-gradient(135deg, #4f46e5, #7c3aed); color: white; box-shadow: 0 4px 15px rgba(79, 70, 229, 0.4); }
        .info-icon { cursor: pointer; display: inline-flex; align-items: center; justify-content: center; margin-left: 10px; font-weight: bold; color: #818cf8; border: 2px solid #818cf8; border-radius: 50%; width: 28px; height: 28px; transition: all 0.3s ease; }
        .info-icon:hover { background-color: #818cf8; color: white; transform: scale(1.1); box-shadow: 0 0 15px #818cf8; }
        .modal-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7); backdrop-filter: blur(5px); z-index: 1000; animation: fadeIn 0.3s; }
        .modal-content { background: #1e293b; border: 1px solid rgba(255, 255, 255, 0.1); animation: slideIn 0.3s; }
        .modal-close { transition: color 0.2s ease; } .modal-close:hover { color: #ef4444; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slideIn { from { transform: translateY(-30px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        input[type="range"] { -webkit-appearance: none; appearance: none; width: 100%; height: 8px; background: #334155; border-radius: 9999px; outline: none; transition: background 0.3s; background-image: linear-gradient(#818cf8, #818cf8); background-size: 50% 100%; background-repeat: no-repeat; }
        input[type="range"]::-webkit-slider-thumb { -webkit-appearance: none; appearance: none; width: 20px; height: 20px; background: white; cursor: pointer; border-radius: 50%; border: 4px solid #818cf8; transition: transform 0.2s ease; }
        input[type="range"]::-webkit-slider-thumb:hover { transform: scale(1.2); }
        .sim-canvas { border-radius: 0.75rem; border: 1px solid rgba(255, 255, 255, 0.1); background-color: #020617; }
        .prose-dark { color: #cbd5e1; } .prose-dark h3 { color: #a78bfa; } .prose-dark code { color: #f87171; background-color: #334155; padding: 2px 5px; border-radius: 4px; } .prose-dark ul>li::marker { color: #818cf8; }
    </style>
</head>
<body>

    <div class="container mx-auto p-4 md:p-8">
        <header class="text-center mb-10">
            <h1 class="text-4xl md:text-6xl font-bold text-white mb-4 tracking-tight">The Comprehensive Process Laboratory</h1>
            <p class="text-xl text-slate-400">An Integrated Research Tool for Exploring Emergence, Randomness, and Meaning</p>
        </header>

        <!-- Dynamic Tab Navigation will be injected here -->
        <div id="tab-navigation" class="mb-8"></div>

        <!-- Dynamic Tab Content will be injected here -->
        <div id="tab-container"></div>
    </div>

    <!-- Centralized Info Modal -->
    <div id="info-modal" class="modal-overlay items-center justify-center p-4"></div>

<script>
document.addEventListener('DOMContentLoaded', () => {

    // --- UTILITIES & HELPERS ---
    const Utils = {
        generateNormalRandom(mean = 0, stdDev = 1) {
            let u1 = 0, u2 = 0;
            while (u1 === 0) u1 = Math.random();
            while (u2 === 0) u2 = Math.random();
            const z = Math.sqrt(-2.0 * Math.log(u1)) * Math.cos(2.0 * Math.PI * u2);
            return z * stdDev + mean;
        },
        updateSlider(slider) {
            if (!slider) return;
            const value = (slider.value - slider.min) / (slider.max - slider.min) * 100;
            slider.style.backgroundSize = `${value}% 100%`;
            const label = document.querySelector(`label[for="${slider.id}"]`);
            if(label) label.querySelector('span').textContent = slider.value;
        },
        createChart(canvas, config) {
            const chartDefaults = {
                options: {
                    responsive: true, maintainAspectRatio: false, animation: { duration: 0 },
                    plugins: { legend: { labels: { color: 'white', font: { size: 14 } } } },
                    scales: {
                        x: { title: { display: true, color: 'white', font: { size: 14, weight: 'bold' } }, ticks: { color: 'rgba(255,255,255,0.7)' }, grid: { color: 'rgba(255,255,255,0.1)' } },
                        y: { title: { display: true, color: 'white', font: { size: 14, weight: 'bold' } }, ticks: { color: 'rgba(255,255,255,0.7)' }, grid: { color: 'rgba(255,255,255,0.1)' } }
                    }
                }
            };
            return new Chart(canvas.getContext('2d'), { ...config, ...chartDefaults });
        },
        debounce(func, wait) {
            let timeout;
            return function executedFunction(...args) {
                const later = () => {
                    clearTimeout(timeout);
                    func(...args);
                };
                clearTimeout(timeout);
                timeout = setTimeout(later, wait);
            };
        }
    };

    // --- DYNAMIC HTML TEMPLATES ---
    const Templates = {
        createSlider(id, label, { min, max, value, step = 1 }) {
            return `<div class="mb-4">
                        <label for="${id}" class="block text-sm font-medium text-slate-300 mb-2">${label}: <span>${value}</span></label>
                        <input type="range" id="${id}" min="${min}" max="${max}" value="${value}" step="${step}">
                    </div>`;
        },
        createButton(id, text, primary = true, extraClasses = '') {
            const baseClasses = 'w-full font-semibold py-2 px-4 rounded-lg shadow-md transition-transform transform hover:scale-105';
            const colorClasses = primary ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-600 text-white hover:bg-slate-700';
            return `<button id="${id}" class="${baseClasses} ${colorClasses} ${extraClasses}">${text}</button>`;
        }
    };

    // --- BASE SIMULATOR CLASS ---
    class Simulator {
        constructor(id) {
            this.id = id;
            this.container = document.getElementById(id);
            if (!this.container) throw new Error(`Container for simulator #${id} not found!`);

            this.isInitialized = false;
            this.animationFrameId = null;
            this.charts = {};

            // Render the simulator's specific HTML into its container
            this.container.innerHTML = this.constructor.getHTML();
        }

        init() {
            if (this.isInitialized) return;
            try {
                this.cacheDOMElements();
                this.addEventListeners();
                this.container.querySelectorAll('input[type="range"]').forEach(Utils.updateSlider);
                this.isInitialized = true;
            } catch (e) {
                console.error(`Initialization failed for ${this.constructor.title}:`, e);
            }
        }

        run() { /* Override in subclasses */ }
        stop() {
            if (this.animationFrameId) {
                cancelAnimationFrame(this.animationFrameId);
                this.animationFrameId = null;
            }
        }

        // Default lifecycle methods
        cacheDOMElements() { /* To be implemented by child */ }
        addEventListeners() { /* To be implemented by child */ }
    }

    // --- MAIN APPLICATION CONTROLLER ---
    class MainApp {
        constructor() {
            this.simulators = {};
            this.activeTabId = null;
            this.infoModal = this.setupInfoModal();

            this.simulatorRegistry = {
                'Communication & Meaning': {
                    'mamc-simulator': { title: 'MAMC Laboratory', class: MAMCSimulator }
                },
                'Growth & Structure': {
                    'ca-simulator': { title: '2D Cellular Automata', class: CellularAutomataSimulator },
                    'lsystem-simulator': { title: 'L-System Growth', class: LSystemSimulator },
                    'branching-simulator': { title: 'Stochastic Branching', class: BranchingSimulator }
                },
                'Stochastic Processes': {
                    'random-walk-simulator': { title: 'Random Walks (1D/2D/3D)', class: RandomWalkSimulator },
                    'galton-watson-simulator': { title: 'Branching Processes', class: GaltonWatsonSimulator },
                    'financial-models-simulator': { title: 'Financial Models', class: FinancialModelsSimulator }
                }
            };

            this.init();
        }

        init() {
            this.setupDOM();
            this.instantiateSimulators();
            this.addGlobalEventListeners();

            // Activate the first tab by default
            const firstTabId = Object.keys(this.simulators)[0];
            this.switchTab(firstTabId);
        }

        setupDOM() {
            const tabContainer = document.getElementById('tab-container');
            const navContainer = document.getElementById('tab-navigation');

            for (const groupName in this.simulatorRegistry) {
                const group = this.simulatorRegistry[groupName];
                navContainer.innerHTML += `<div class="text-sm font-semibold text-center text-slate-400 mt-6 mb-2 uppercase tracking-wider">${groupName}</div>`;
                const nav = document.createElement('nav');
                nav.className = 'flex flex-wrap justify-center -mb-px gap-2';

                for (const id in group) {
                    const sim = group[id];
                    // Create tab content container
                    const contentDiv = document.createElement('div');
                    contentDiv.id = id;
                    contentDiv.className = 'tab-content';
                    tabContainer.appendChild(contentDiv);

                    // Create tab button
                    const tabButton = document.createElement('button');
                    tabButton.className = 'tab py-3 px-5 font-semibold text-slate-300 border-b-2 border-transparent rounded-t-lg';
                    tabButton.dataset.tab = id;
                    tabButton.textContent = sim.title;
                    nav.appendChild(tabButton);
                }
                navContainer.appendChild(nav);
            }
        }

        instantiateSimulators() {
            for (const groupName in this.simulatorRegistry) {
                for (const id in this.simulatorRegistry[groupName]) {
                    const simInfo = this.simulatorRegistry[groupName][id];
                    this.simulators[id] = new simInfo.class(id);
                }
            }
        }

        addGlobalEventListeners() {
            document.querySelectorAll('.tab').forEach(tab => {
                tab.addEventListener('click', () => this.switchTab(tab.dataset.tab));
            });
            document.body.addEventListener('click', (e) => {
                if (e.target.matches('.info-icon')) this.infoModal.open(e.target.dataset.info);
            });
            window.addEventListener('resize', Utils.debounce(() => {
                if (this.activeTabId && this.simulators[this.activeTabId] && typeof this.simulators[this.activeTabId].onResize === 'function') {
                    this.simulators[this.activeTabId].onResize();
                }
            }, 200));
        }

        switchTab(targetId) {
            if (this.activeTabId === targetId) return;
            if (this.activeTabId) this.simulators[this.activeTabId].stop();

            this.activeTabId = targetId;

            document.querySelectorAll('.tab').forEach(t => t.classList.toggle('active', t.dataset.tab === targetId));
            document.querySelectorAll('.tab-content').forEach(c => c.classList.toggle('active', c.id === targetId));

            const newSim = this.simulators[targetId];
            if (newSim) {
                newSim.init(); // Safe to call multiple times
                if(typeof newSim.run === 'function') newSim.run();
            }
        }

        setupInfoModal() {
            const modalContainer = document.getElementById('info-modal');
            const infoContent = {
                // ... (content for all simulators)
                'mamc-simulator': { title: 'MAMC Laboratory', body: `<p>This laboratory operationalizes the MAMC framework, allowing you to quantify and compare any communication act.</p> <ul class="list-disc pl-5 space-y-2 mt-2"> <li><strong>The Axes:</strong> Each slider corresponds to a metric within one of the three core axes: Message Anatomy (What), Communication Ecology (Who/Where), and Interactional Physics (When/How).</li> <li><strong>Communication Signature:</strong> The radar chart visualizes the "shape" of the communication. A larger, fuller shape indicates a more complex act.</li> <li><strong>Communicative Density (D):</strong> This single, calculated score represents the total informational and interactive load of the act.</li> <li><strong>Application:</strong> Use this tool to diagnose communication problems or to design new communication systems.</li> </ul>` },
                'ca-simulator': { title: '2D Cellular Automata', body: '<p>A 2D cellular automaton is a grid of cells that evolves over time. The state of each cell in the next generation is determined by a simple set of rules based on the states of its neighbors. This demonstrates <strong>emergent behavior</strong>, where complex global patterns arise from simple local interactions.</p><ul><li><strong>Rules (S/B):</strong> "S" stands for Survival (a living cell needs this many neighbors to live). "B" is for Birth (a dead cell needs this many neighbors to become alive). S23/B3 is Conway\'s Game of Life.</li></ul>' },
                'lsystem-simulator': { title: 'L-System Growth', body: '<p>Lindenmayer systems are a type of formal grammar used to generate self-similar, fractal structures, often mimicking the growth of plants. It starts with an initial string (axiom) and iteratively applies rules to generate a long instruction string for a "turtle" graphics system.</p><ul><li><strong>F:</strong> Draw Forward</li><li><strong>+/-:</strong> Turn Left/Right</li><li><strong>[:</strong> Save State (position & angle)</li><li><strong>]:</strong> Restore State</li></ul>' },
                'branching-simulator': { title: 'Stochastic Branching', body: '<p>This simulator generates tree-like fractals using recursion. At the end of each branch, two new branches are created with slightly randomized angles and reduced length. The "stochastic" (random) element creates more organic, natural-looking structures compared to deterministic L-Systems.</p>' },
                'random-walk-simulator': { title: 'Random Walks & Brownian Motion', body: '<p>A random walk is a path made of a succession of random steps. It\'s a fundamental model for stochastic processes.</p><ul><li><strong>Brownian Motion:</strong> This simulation uses steps drawn from a normal (Gaussian) distribution, providing a continuous-space model analogous to the motion of particles in a fluid.</li><li><strong>Dimensions:</strong> The 1D and 2D walkers exist on a plane, while the 3D walker uses Three.js for a full 3D visualization.</li><li><strong>Mean Squared Displacement (MSD):</strong> For a standard random walk, the MSD is proportional to time. This chart helps visualize the diffusive nature of the process.</li></ul>' },
                'galton-watson-simulator': { title: 'Galton-Watson Branching Process', body: '<p>This process models population dynamics where each individual produces a random number of offspring according to fixed probabilities. The key question is whether the population survives or goes extinct.</p><ul><li><strong>Mean Offspring (μ):</strong> Calculated as <code>0*P0 + 1*P1 + 2*P2</code>. If μ ≤ 1, extinction is almost certain. If μ > 1, there\'s a chance of survival.</li><li><strong>Visualization:</strong> The top chart shows individual simulation trajectories (on a log scale to handle explosive growth). The bottom chart shows the final statistics of extinction vs. survival across all runs.</li></ul>' },
                'financial-models-simulator': { title: 'Stochastic Financial Models', body: `<div class="prose-dark max-w-none"> <p>These models use stochastic differential equations (SDEs) to simulate asset price paths. They are foundational to quantitative finance.</p> <ul> <li><strong>Geometric Brownian Motion (GBM):</strong> The standard model for stock prices. <code>dS = μS dt + σS dW</code></li> <li><strong>Mean-Reversion (Ornstein-Uhlenbeck):</strong> Models assets that tend to revert to a long-term average (e.g., interest rates). <code>dX = κ(θ - X) dt + σ dW</code></li> <li><strong>Jump-Diffusion (Merton Model):</strong> Extends GBM by adding sudden, random price "jumps" to model market shocks.</li> </ul> <p>The animated drawing visualizes the path-dependent nature of these processes over time.</p></div>` },
            };

            const close = () => modalContainer.style.display = 'none';
            return {
                open: (key) => {
                    const content = infoContent[key];
                    if (!content) return;
                    modalContainer.innerHTML = `
                        <div class="modal-content max-w-2xl w-11/12 max-h-[85vh] overflow-y-auto p-8 rounded-2xl relative">
                            <span class="modal-close absolute top-4 right-5 text-3xl cursor-pointer text-slate-400">&times;</span>
                            <h2 class="text-3xl font-bold mb-6 text-white">${content.title}</h2>
                            <div class="prose-dark max-w-none">${content.body}</div>
                        </div>`;
                    modalContainer.style.display = 'flex';
                    modalContainer.querySelector('.modal-close').onclick = close;
                    modalContainer.onclick = (e) => { if (e.target === modalContainer) close(); };
                }
            };
        }
    }

    // --- CONCRETE SIMULATOR CLASSES ---

    class MAMCSimulator extends Simulator {
        static title = 'MAMC Laboratory';
        static getHTML() {
            return `<div class="glass-card p-6 md:p-8 rounded-2xl">
                <header class="text-center mb-8">
                    <h1 class="text-3xl md:text-4xl font-bold text-white inline-block">MAMC Laboratory</h1><span class="info-icon" data-info="mamc-simulator">i</span>
                    <p class="text-md text-slate-400 mt-2">Model, visualize, and quantify any act of communication.</p>
                </header>
                <div class="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <div class="lg:col-span-1 glass-card p-6 rounded-xl space-y-4">
                        <h2 class="text-2xl font-semibold text-white mb-4">Communication Profile</h2>
                        <select id="mamc-presets" class="w-full bg-slate-700 border-slate-600 rounded-lg p-2 text-white mb-4"></select>
                        <h3 class="text-lg font-semibold text-indigo-400 pt-2">Axis M: Message Anatomy</h3>
                        ${Templates.createSlider('m_modality_richness', 'Modality Richness (Mᵣ)', {min:0, max:1, value:0.5, step:0.05})}
                        ${Templates.createSlider('m_symbolic_complexity', 'Symbolic Complexity (Mₛ)', {min:0, max:1, value:0.5, step:0.05})}
                        <h3 class="text-lg font-semibold text-indigo-400 pt-2">Axis E: Communication Ecology</h3>
                        ${Templates.createSlider('e_scale_of_address', 'Scale of Address (Eₛ)', {min:0, max:1, value:0.5, step:0.05})}
                        ${Templates.createSlider('e_relational_asymmetry', 'Relational Asymmetry (Eₐ)', {min:0, max:1, value:0.5, step:0.05})}
                        <h3 class="text-lg font-semibold text-indigo-400 pt-2">Axis T: Interactional Physics</h3>
                        ${Templates.createSlider('t_synchronicity', 'Synchronicity (Tₛ)', {min:0, max:1, value:0.5, step:0.05})}
                        ${Templates.createSlider('t_persistence', 'Persistence (Tₚ)', {min:0, max:1, value:0.5, step:0.05})}
                        ${Templates.createSlider('t_feedback_modality', 'Feedback Modality (T𝒻)', {min:0, max:1, value:0.5, step:0.05})}
                        <div class="flex items-center pt-4"><input id="mamc_networked" type="checkbox" class="h-4 w-4 rounded accent-indigo-500"><label for="mamc_networked" class="ml-2 text-sm">Digitally Networked (η > 1)</label></div>
                    </div>
                    <div class="lg:col-span-2 space-y-8">
                        <div class="glass-card p-6 rounded-xl"><h2 class="text-2xl font-semibold mb-4 text-center text-white">Communication Signature</h2><div class="w-full h-80"><canvas id="mamc-radar-chart"></canvas></div></div>
                        <div class="glass-card p-6 rounded-xl">
                            <h2 class="text-2xl font-semibold mb-4 text-center text-white">Comparative Analysis</h2>
                            <div class="text-center mb-6"><p class="text-lg text-slate-400">Current Profile's Communicative Density (D):</p><p id="mamc-density-score" class="text-5xl font-bold text-white">1.00</p></div>
                            <div class="flex flex-col sm:flex-row gap-4 mb-6"><input type="text" id="mamc-profile-name" placeholder="Enter profile name..." class="flex-grow p-2 bg-slate-700 border border-slate-600 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 text-white"><button id="mamc-save-profile-btn" class="w-full sm:w-auto bg-indigo-600 text-white font-semibold py-2 px-6 rounded-lg shadow-md hover:bg-indigo-700 transition-colors">Save Profile</button></div>
                            <div class="w-full h-80"><canvas id="mamc-comparison-chart"></canvas></div>
                        </div>
                    </div>
                </div>
            </div>`;
        }

        cacheDOMElements() {
            this.elements = {
                presets: this.container.querySelector('#mamc-presets'),
                sliders: { mr: this.container.querySelector('#m_modality_richness'), ms: this.container.querySelector('#m_symbolic_complexity'), es: this.container.querySelector('#e_scale_of_address'), ea: this.container.querySelector('#e_relational_asymmetry'), ts: this.container.querySelector('#t_synchronicity'), tp: this.container.querySelector('#t_persistence'), tf: this.container.querySelector('#t_feedback_modality') },
                networked: this.container.querySelector('#mamc_networked'),
                densityScore: this.container.querySelector('#mamc-density-score'),
                profileName: this.container.querySelector('#mamc-profile-name'),
                saveBtn: this.container.querySelector('#mamc-save-profile-btn'),
            };
            this.savedProfiles = [];
            this.presetsData = {
                '-- Custom --': null,
                'Neolithic Cave Painting': { mr: 0.2, ms: 0.3, es: 0.1, ea: 0.8, ts: 0.0, tp: 0.9, tf: 0.0, networked: false },
                '19th Century Printed Book': { mr: 0.2, ms: 0.8, es: 0.8, ea: 0.9, ts: 0.0, tp: 0.9, tf: 0.1, networked: false },
                'Live Twitch Stream': { mr: 0.9, ms: 0.7, es: 0.9, ea: 0.4, ts: 1.0, tp: 0.6, tf: 0.9, networked: true },
                'SMS Text Message': { mr: 0.2, ms: 0.4, es: 0.2, ea: 0.5, ts: 0.2, tp: 0.8, tf: 0.3, networked: true },
                'Collaborative VR Meeting': { mr: 1.0, ms: 0.8, es: 0.4, ea: 0.3, ts: 1.0, tp: 0.5, tf: 1.0, networked: true },
            };
            // Populate presets dropdown
            this.elements.presets.innerHTML = Object.keys(this.presetsData).map(name => `<option value="${name}">${name}</option>`).join('');
        }

        addEventListeners() {
            Object.values(this.elements.sliders).forEach(s => s.addEventListener('input', () => { this.elements.presets.value = '-- Custom --'; this.update(); Utils.updateSlider(s); }));
            this.elements.networked.addEventListener('change', () => { this.elements.presets.value = '-- Custom --'; this.update(); });
            this.elements.presets.addEventListener('change', (e) => this.loadPreset(e.target.value));
            this.elements.saveBtn.addEventListener('click', () => this.saveProfile());
        }

        run() {
            this.charts.radar = Utils.createChart(this.container.querySelector('#mamc-radar-chart'), { type: 'radar', options: { scales: { r: { beginAtZero: true, max: 1, ticks: { display: false }, grid: { color: 'rgba(255,255,255,0.2)' }, pointLabels: { color: 'white', font: { size: 12 } }, angleLines: { color: 'rgba(255,255,255,0.2)' } } } } });
            this.charts.comparison = Utils.createChart(this.container.querySelector('#mamc-comparison-chart'), { type: 'bar', options: { indexAxis: 'y' } });
            this.loadPreset('Live Twitch Stream');
        }

        loadPreset(name) {
            const preset = this.presetsData[name];
            if (!preset) return;
            Object.keys(preset).forEach(key => {
                if (this.elements.sliders[key]) { this.elements.sliders[key].value = preset[key]; Utils.updateSlider(this.elements.sliders[key]); } 
                else if (key === 'networked') this.elements.networked.checked = preset[key];
            });
            this.update();
        }

        update() {
            const v = {};
