        addEventListeners() { /* ... (Same as previous implementation) ... */ this.elements.runBtn.addEventListener('click',()=>this.run()),this.elements.pauseBtn.addEventListener('click',()=>this.stop()),this.elements.stepBtn.addEventListener('click',()=>this.tick()),this.elements.resetBtn.addEventListener('click',()=>this.reset()),this.elements.cellSize.addEventListener('input',()=>{Utils.updateSlider(this.elements.cellSize),this.reset()}),this.elements.speed.addEventListener('input',()=>Utils.updateSlider(this.elements.speed)),this.elements.presets.addEventListener('change',e=>this.loadPreset(e.target.value));let e=!1;this.canvas.addEventListener('mousedown',t=>{e=!0,this.drawOnCanvas(t)}),this.canvas.addEventListener('mousemove',t=>{e&&this.drawOnCanvas(t)}),this.canvas.addEventListener('mouseup',()=>e=!1),this.canvas.addEventListener('mouseleave',()=>e=!1) }
        loadPreset(name) { const preset = this.rulePresets[name]; if (preset) { this.elements.survival.value = preset.s; this.elements.birth.value = preset.b; } }
