        countNeighbors(x, y) { let count = 0; for (let i = -1; i <= 1; i++) { for (let j = -1; j <= 1; j++) { if (i === 0 && j === 0) continue; const col = (x + j + this.cols) % this.cols; const row = (y + i + this.rows) % this.rows; count += this.grid[row][col]; } } return count; }
