        cacheDOMElements() {
            this.canvas = this.container.querySelector('#lsys-canvas');
            this.ctx = this.canvas.getContext('2d');
            this.elements = {
                presets: this.container.querySelector('#lsys-presets'),
                iterations: this.container.querySelector('#lsys-iterations'),
                angle: this.container.querySelector('#lsys-angle'),
                generateBtn: this.container.querySelector('#lsys-generate-btn'),
            };
            this.presets = {
                'Fractal Plant': { axiom: 'X', rules: { 'X': 'F+[[X]-X]-F[-FX]+X', 'F': 'FF' }, angle: 25, startAngle: -90, iterations: 5 },
                'Koch Curve': { axiom: 'F', rules: { 'F': 'F+F-F-F+F' }, angle: 90, startAngle: 0, iterations: 3 },
                'Sierpinski Triangle': { axiom: 'F-G-G', rules: { 'F': 'F-G+F+G-F', 'G': 'GG' }, angle: 120, startAngle: 0, iterations: 5 },
                'Dragon Curve': { axiom: 'FX', rules: { 'X': 'X+YF+', 'Y': '-FX-Y' }, angle: 90, startAngle: 0, iterations: 10 },
            };
            this.elements.presets.innerHTML = Object.keys(this.presets).map(name => `<option value="${name}">${name}</option>`).join('');
        }
        addEventListeners() {
            this.elements.generateBtn.addEventListener('click', () => this.run());
            this.elements.presets.addEventListener('change', (e) => this.loadPreset(e.target.value));
            ['iterations', 'angle'].forEach(id => this.elements[id].addEventListener('input', () => Utils.updateSlider(this.elements[id])));
        }
        loadPreset(name) {
            const preset = this.presets[name];
            if (preset) {
                this.elements.angle.value = preset.angle;
                this.elements.iterations.value = preset.iterations;
                Utils.updateSlider(this.elements.angle);
                Utils.updateSlider(this.elements.iterations);
            }
        }
        run() {
            const presetName = this.elements.presets.value;
            const preset = this.presets[presetName];
            const iterations = parseInt(this.elements.iterations.value);
            const angle = parseInt(this.elements.angle.value);

            let currentString = preset.axiom;
            for (let i = 0; i < iterations; i++) {
                let nextString = '';
                for (const char of currentString) {
                    nextString += preset.rules[char] || char;
                }
                currentString = nextString;
            }
            this.draw(currentString, angle, preset.startAngle);
        }
        draw(str, angle, startAngle) {
            this.onResize(); // Clear and resize
            this.ctx.strokeStyle = '#e2e8f0';
            this.ctx.lineWidth = 1;
            this.ctx.beginPath();

            // Center the drawing
            this.ctx.translate(this.canvas.width / 2, this.canvas.height);
            this.ctx.moveTo(0, 0);
            this.ctx.rotate(startAngle * Math.PI / 180);

            const stateStack = [];
            const length = 5;

            for (const char of str) {
                switch (char) {
                    case 'F':
                    case 'G':
                        this.ctx.lineTo(0, -length);
                        this.ctx.translate(0, -length);
                        break;
                    case '+':
                        this.ctx.rotate(angle * Math.PI / 180);
                        break;
                    case '-':
                        this.ctx.rotate(-angle * Math.PI / 180);
                        break;
                    case '[':
                        stateStack.push(this.ctx.getTransform());
                        break;
                    case ']':
                        this.ctx.setTransform(stateStack.pop());
                        break;
                }
            }
            this.ctx.stroke();
            this.ctx.setTransform(1, 0, 0, 1, 0, 0); // Reset transform
        }
        init() { super.init(); this.loadPreset('Fractal Plant'); this.run(); }
        onResize() {
            const container = this.canvas.parentElement;
            this.canvas.width = container.clientWidth;
            this.canvas.height = container.clientHeight;
            this.ctx.fillStyle = '#020617';
            this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
        }
    }

