            Object.values(this.elements).forEach(el => {
                if (el.type === 'range') el.addEventListener('input', () => Utils.updateSlider(el));
            });
        }
        run() {
            this.onResize();
            const startX = this.canvas.width / 2;
            const startY = this.canvas.height;
            const startLength = this.canvas.height / 4.5;
            this.ctx.strokeStyle = '#e2e8f0';
            this.drawBranch(startX, startY, -90, startLength, 0);
        }
        drawBranch(x, y, angle, length, depth) {
            if (depth > parseInt(this.elements.depth.value)) return;

            const randFactor = parseFloat(this.elements.random.value);
            const angleDeg = parseFloat(this.elements.angle.value);
            const decay = parseFloat(this.elements.decay.value);

            this.ctx.beginPath();
            this.ctx.moveTo(x, y);

            const endX = x + length * Math.cos(angle * Math.PI / 180);
            const endY = y + length * Math.sin(angle * Math.PI / 180);

            this.ctx.lineTo(endX, endY);
            this.ctx.lineWidth = Math.max(1, (parseInt(this.elements.depth.value) - depth) / 2);
            this.ctx.stroke();

            const newLength = length * decay;
            const angle1 = angle - angleDeg + (Math.random() - 0.5) * angleDeg * randFactor;
            const angle2 = angle + angleDeg + (Math.random() - 0.5) * angleDeg * randFactor;

            this.drawBranch(endX, endY, angle1, newLength, depth + 1);
            this.drawBranch(endX, endY, angle2, newLength, depth + 1);
        }
        init() { super.init(); this.run(); }
        onResize() {
            const container = this.canvas.parentElement;
            this.canvas.width = container.clientWidth;
            this.canvas.height = container.clientHeight;
            this.ctx.fillStyle = '#020617';
            this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
        }
    }

