        cacheDOMElements() {
            this.visContainer = this.container.querySelector('#rw-vis-container');
            this.canvas = this.container.querySelector('#rw-canvas');
            this.msdCanvas = this.container.querySelector('#rw-msd-chart');
            this.elements = {
                dimSelect: this.container.querySelector('#rw-dim-select'),
                walkers: this.container.querySelector('#rw-walkers'),
                steps: this.container.querySelector('#rw-steps'),
                runBtn: this.container.querySelector('#rw-run-btn'),
            };
