        }
        init() { super.init(); this.run(); }
        run() {
            this.stop();
            this.dimension === 3 ? this.run3D() : this.run2D();
        }

        generateWalks() {
            const numWalkers = parseInt(this.elements.walkers.value);
            const numSteps = parseInt(this.elements.steps.value);
            const walks = [];
            const msd = new Array(numSteps).fill(0);

            for (let i = 0; i < numWalkers; i++) {
                const path = [new THREE.Vector3(0, 0, 0)];
                for (let j = 1; j < numSteps; j++) {
                    const prev = path[j - 1];
                    const step = new THREE.Vector3(Utils.generateNormalRandom(), this.dimension > 1 ? Utils.generateNormalRandom() : 0, this.dimension > 2 ? Utils.generateNormalRandom() : 0);
                    path.push(prev.clone().add(step));
                }
                walks.push(path);
            }

            // Calculate MSD
            for (let t = 0; t < numSteps; t++) {
                let sumSqDist = 0;
                for (let i = 0; i < numWalkers; i++) {
                    sumSqDist += walks[i][t].lengthSq();
                }
                msd[t] = sumSqDist / numWalkers;
            }

            return { walks, msd };
        }

