            this.drawMSDChart(msd);

            const ctx = this.canvas.getContext('2d');
            ctx.fillStyle = '#020617';
            ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

            walks.forEach(path => {
                ctx.beginPath();
                ctx.moveTo(this.canvas.width / 2, this.canvas.height / 2);
