            try {
                const distStr = this.elements.dist.value;
                const dist = JSON.parse(distStr);
                const numSims = parseInt(this.elements.sims.value);
                const maxGens = parseInt(this.elements.gens.value);

                const cdf = [];
                let cumulative = 0;
                let mean = 0;
                for (const offspring in dist) {
                    const prob = dist[offspring];
                    cumulative += prob;
                    cdf.push({ offspring: parseInt(offspring), prob: cumulative });
                    mean += parseInt(offspring) * prob;
                }
                if (Math.abs(cumulative - 1.0) > 1e-6) throw new Error("Probabilities must sum to 1.");

                const sampleOffspring = () => {
                    const r = Math.random();
                    for (const item of cdf) {
                        if (r < item.prob) return item.offspring;
                    }
                    return cdf[cdf.length - 1].offspring;
                };

                const allPaths = [];
                const finalSizes = [];
                let extinctions = 0;

                for (let i = 0; i < numSims; i++) {
                    let population = [1];
                    for (let g = 0; g < maxGens; g++) {
                        let nextGenSize = 0;
                        const currentSize = population[population.length - 1];
                        if (currentSize === 0 || currentSize > 10000) { // Cap population
                             population.push(currentSize);
                             continue;
                        }
                        for (let p = 0; p < currentSize; p++) {
                            nextGenSize += sampleOffspring();
                        }
                        population.push(nextGenSize);
                    }
                    allPaths.push(population);
                    const finalSize = population[population.length - 1];
                    finalSizes.push(finalSize);
                    if (finalSize === 0) extinctions++;
                }

                this.drawPathsChart(allPaths, maxGens);
                this.drawHistChart(finalSizes);
                this.updateSummary(extinctions, numSims, mean);

