        addGlobalEventListeners() { document.querySelectorAll('.tab').forEach(t => t.addEventListener('click', () => this.switchTab(t.dataset.tab))); document.body.addEventListener('click', (e) => { if (e.target.matches('.info-icon')) this.infoModal.open(e.target.dataset.info); }); window.addEventListener('resize', Utils.debounce(() => { if (this.activeTabId && this.simulators[this.activeTabId].onResize) this.simulators[this.activeTabId].onResize(); }, 200)); }
