        addEventListeners() { const updateOnChange = () => { this.elements.presets.value = '-- Custom --'; this.update(); }; Object.values(this.elements.sliders).forEach(s => { s.addEventListener('input', updateOnChange); s.addEventListener('input', () => Utils.updateSlider(s)); }); this.elements.networked.addEventListener('change', updateOnChange); this.elements.presets.addEventListener('change', (e) => this.loadPreset(e.target.value)); this.elements.saveBtn.addEventListener('click', () => this.saveProfile()); }
