        update() { const v={};for(const k in this.elements.sliders) v[k] = parseFloat(this.elements.sliders[k].value); v.networked=this.elements.networked.checked; const fM=v.mr+v.ms, gE=v.es+v.ea, hT=v.ts+v.tp+v.tf; const eta=v.networked?1.5:1.0; const density=eta*fM*gE*hT*5; this.elements.densityScore.textContent=density.toFixed(2); this.charts.radar.data={labels:['Modality (Mᵣ)','Symbolism (Mₛ)','Scale (Eₛ)','Asymmetry (Eₐ)','Sync (Tₛ)','Persistence (Tₚ)','Feedback (T𝒻)'],datasets:[{data:[v.mr,v.ms,v.es,v.ea,v.ts,v.tp,v.tf],fill:true,backgroundColor:'rgba(129,140,248,0.4)',borderColor:'#a78bfa',pointBackgroundColor:'white'}]}; this.charts.radar.update();}
        saveProfile() { const name = this.elements.profileName.value.trim(); if (!name) { alert('Please enter a profile name.'); return; } const density = parseFloat(this.elements.densityScore.textContent); const existingIndex = this.savedProfiles.findIndex(p => p.name === name); if (existingIndex > -1) { this.savedProfiles[existingIndex].density = density; } else { this.savedProfiles.push({ name, density }); } this.elements.profileName.value = ''; this.updateComparisonChart(); }
        updateComparisonChart() { this.savedProfiles.sort((a, b) => a.density - b.density); this.charts.comparison.data.labels = this.savedProfiles.map(p => p.name); this.charts.comparison.data.datasets[0].data = this.savedProfiles.map(p => p.density); this.charts.comparison.data.datasets[0].backgroundColor = 'rgba(129, 140, 248, 0.7)'; this.charts.comparison.update(); }
