    class CellularAutomataSimulator extends Simulator { /* ... Restored click-drawing, presets, and original logic ... */
        static title = 'Cellular Automata';
        static getHTML() { /* ... includes preset dropdown and tools div ... */ return `<div class="glass-card p-6 md:p-8 rounded-2xl"><header class="text-center mb-8"><h1 class="text-3xl md:text-4xl font-bold text-white inline-block">Cellular Automata</h1><span class="info-icon" data-info="ca-simulator">i</span></header><div class="grid grid-cols-1 lg:grid-cols-4 gap-8"><div class="lg:col-span-1 glass-card p-6 rounded-xl space-y-4"><h2 class="text-2xl font-semibold text-white mb-4">Controls</h2><div><label for="ca-presets" class="block text-sm text-slate-300 mb-2">Patterns</label><select id="ca-presets" class="w-full bg-slate-700 p-2 rounded-lg"></select></div><div><label for="ca-rules" class="block text-sm text-slate-300 mb-2">Rules (S/B)</label><input type="text" id="ca-rules" value="23/3" class="w-full bg-slate-700 p-2 rounded-lg font-mono"></div>${Templates.createSlider('ca-speed', 'Speed (ms)', {min:0,max:500,value:50})}${Templates.createSlider('ca-cell-size', 'Cell Size', {min:2,max:20,value:8})}<div class="grid grid-cols-2 gap-4 pt-4">${Templates.createButton('ca-run-btn', 'Run')}${Templates.createButton('ca-pause-btn', 'Pause', false)}${Templates.createButton('ca-step-btn', 'Step', false)}${Templates.createButton('ca-reset-btn', 'Randomize')}</div><div class="pt-4 border-t border-slate-600 space-y-2"><h3 class="text-lg font-semibold text-white">Tools</h3><div class="grid grid-cols-2 gap-4">${Templates.createButton('ca-snapshot-btn', 'Snapshot')}${Templates.createButton('ca-record-btn', 'Record Video', false, 'record-btn')}</div></div></div><div class="lg:col-span-3 min-h-[60vh] rounded-xl overflow-hidden"><canvas id="ca-canvas" class="sim-canvas"></canvas></div></div></div>`; }
        cacheDOMElements() { this.canvas=this.container.querySelector('#ca-canvas'); this.ctx=this.canvas.getContext('2d'); this.elements={presets:this.container.querySelector('#ca-presets'), rules:this.container.querySelector('#ca-rules'), speed:this.container.querySelector('#ca-speed'), cellSize:this.container.querySelector('#ca-cell-size'), runBtn:this.container.querySelector('#ca-run-btn'), pauseBtn:this.container.querySelector('#ca-pause-btn'), stepBtn:this.container.querySelector('#ca-step-btn'), resetBtn:this.container.querySelector('#ca-reset-btn'), snapshotBtn: this.container.querySelector('#ca-snapshot-btn'), recordBtn: this.container.querySelector('#ca-record-btn') }; this.isPaused = false; this.presetData = { 'Random': null, 'Clear': [], 'Glider': [[1,0],[2,1],[0,2],[1,2],[2,2]], 'Acorn': [[1,2],[2,0],[2,2],[4,1],[5,2],[6,2],[7,2]], 'Gosper Gun': [[24,0],[22,1],[24,1],[12,2],[13,2],[20,2],[21,2],[34,2],[35,2],[11,3],[15,3],[20,3],[21,3],[34,3],[35,3],[0,4],[1,4],[10,4],[16,4],[20,4],[21,4],[0,5],[1,5],[10,5],[14,5],[16,5],[17,5],[22,5],[24,5],[10,6],[16,6],[24,6],[11,7],[15,7],[12,8],[13,8]]}; this.elements.presets.innerHTML = Object.keys(this.presetData).map(n => `<option value="${n}">${n}</option>`).join(''); }
        addEventListeners() { this.elements.runBtn.addEventListener('click',()=>this.run()); this.elements.pauseBtn.addEventListener('click',()=>this.togglePause()); this.elements.stepBtn.addEventListener('click',()=>this.tick()); this.elements.resetBtn.addEventListener('click',()=>this.reset('Random')); this.elements.presets.addEventListener('change', e => this.reset(e.target.value)); ['speed','cellSize'].forEach(id => this.elements[id].addEventListener('input', () => Utils.updateSlider(this.elements[id]))); this.elements.cellSize.addEventListener('change', () => this.reset(this.elements.presets.value)); this.canvas.addEventListener('mousedown', e => {this.isDrawing = true; this.drawOnCanvas(e);}); this.canvas.addEventListener('mousemove', e => {if(this.isDrawing) this.drawOnCanvas(e);}); this.canvas.addEventListener('mouseup', () => this.isDrawing = false); this.elements.snapshotBtn.addEventListener('click', () => this.snapshot()); this.elements.recordBtn.addEventListener('click', () => this.toggleRecording()); }
        togglePause() { this.isPaused = !this.isPaused; this.elements.pauseBtn.textContent = this.isPaused ? 'Resume' : 'Pause'; if(!this.isPaused) this.run(); }
        drawOnCanvas(e) { const rect = this.canvas.getBoundingClientRect(); const x=Math.floor((e.clientX - rect.left) / this.cellSize), y=Math.floor((e.clientY - rect.top) / this.cellSize); if(x>=0&&x<this.cols&&y>=0&&y<this.rows) {this.grid[y][x]=1-this.grid[y][x]; this.draw();} }
        init() { super.init(); this.run(); }
        onResize() { if(!this.canvas) return; const container = this.canvas.parentElement; this.canvas.width = container.clientWidth; this.canvas.height = container.clientHeight; this.reset(this.elements.presets.value); }
        reset(presetName) { this.stop(); this.isPaused = true; this.elements.pauseBtn.textContent = 'Resume'; this.cellSize = parseInt(this.elements.cellSize.value); this.cols = Math.floor(this.canvas.width / this.cellSize); this.rows = Math.floor(this.canvas.height / this.cellSize); this.grid = Array.from({length:this.rows}, () => Array(this.cols).fill(0)); const pattern = this.presetData[presetName]; if(pattern) { const offsetX = Math.floor(this.cols/2 - 10), offsetY = Math.floor(this.rows/2 - 5); pattern.forEach(([x,y]) => {const gridX=offsetX+x, gridY=offsetY+y; if(gridX>=0&&gridX<this.cols&&gridY>=0&&gridY<this.rows) this.grid[gridY][gridX] = 1;}); } else if(presetName === 'Random') { this.grid = this.grid.map(row => row.map(() => Math.random() > 0.7 ? 1 : 0)); } this.draw(); }
        run() { this.stop(); this.isPaused = false; this.elements.pauseBtn.textContent = 'Pause'; const loop = () => { if(this.isPaused) return; this.tick(); this.timeoutId = setTimeout(() => { this.animationFrameId = requestAnimationFrame(loop) }, parseInt(this.elements.speed.value)); }; this.animationFrameId = requestAnimationFrame(loop); }
        tick() { const [S,B] = this.elements.rules.value.replace(/[^0-9/]/g, '').split('/').map(r => r.split('').map(Number)); const nextGrid = this.grid.map(arr => [...arr]); for (let y = 0; y < this.rows; y++) for (let x = 0; x < this.cols; x++) { const n = this.countNeighbors(x,y); const isAlive = this.grid[y][x]===1; if(isAlive && !S.includes(n)) nextGrid[y][x]=0; else if(!isAlive && B.includes(n)) nextGrid[y][x]=1; } this.grid = nextGrid; this.draw(); }
        countNeighbors(x,y) { let c=0; for (let i=-1;i<=1;i++) for(let j=-1;j<=1;j++) { if(i===0&&j===0) continue; c+=this.grid[(y+i+this.rows)%this.rows][(x+j+this.cols)%this.cols]; } return c; }
        draw() { this.ctx.fillStyle='#020617'; this.ctx.fillRect(0,0,this.canvas.width,this.canvas.height); this.ctx.fillStyle='#a78bfa'; for (let y=0;y<this.rows;y++) for(let x=0;x<this.cols;x++) if(this.grid[y][x]===1) this.ctx.fillRect(x*this.cellSize,y*this.cellSize,this.cellSize-1,this.cellSize-1); }
    }
